# Safe operators mapping
SAFE_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.BitXor: operator.xor,
    ast.USub: operator.neg,
    ast.UAdd: operator.pos,
}

# Safe functions mapping
SAFE_FUNCTIONS = {
    'abs': abs,
    'round': round,
    'pow': pow,
    'min': min,
    'max': max,
    'sum': sum,
    'len': len,
    # Math functions
    'sin': math.sin,
    'cos': math.cos,
    'tan': math.tan,
    'asin': math.asin,
    'acos': math.acos,
    'atan': math.atan,
    'sqrt': math.sqrt,
    'log': math.log,
    'log10': math.log10,
    'exp': math.exp,
    'ceil': math.ceil,
    'floor': math.floor,
    'factorial': math.factorial,
    'degrees': math.degrees,
    'radians': math.radians,
    'pi': math.pi,
    'e': math.e,
}

def safe_eval_node(node):
    """Safely evaluate an AST node"""
    if isinstance(node, ast.Num):
        return node.n
    elif isinstance(node, ast.Constant):
        if isinstance(node.value, (int, float)):
            return node.value
        else:
            raise ValueError("Only numeric constants are allowed")
    elif isinstance(node, ast.BinOp):
        if type(node.op) not in SAFE_OPERATORS:
            raise ValueError(f"Operator {type(node.op).__name__} is not allowed")
        left = safe_eval_node(node.left)
        right = safe_eval_node(node.right)
        return SAFE_OPERATORS[type(node.op)](left, right)
    elif isinstance(node, ast.UnaryOp):
        if type(node.op) not in SAFE_OPERATORS:
            raise ValueError(f"Unary operator {type(node.op).__name__} is not allowed")
        operand = safe_eval_node(node.operand)
        return SAFE_OPERATORS[type(node.op)](operand)
    elif isinstance(node, ast.Call):
        if isinstance(node.func, ast.Name):
            func_name = node.func.id
            if func_name not in SAFE_FUNCTIONS:
                raise ValueError(f"Function {func_name} is not allowed")
            func = SAFE_FUNCTIONS[func_name]
            args = [safe_eval_node(arg) for arg in node.args]
            return func(*args)
        else:
            raise ValueError("Only direct function calls are allowed")
    elif isinstance(node, ast.Name):
        if node.id in SAFE_FUNCTIONS and callable(SAFE_FUNCTIONS[node.id]):
            raise ValueError(f"Function {node.id} must be called")
        if node.id in SAFE_FUNCTIONS:
            return SAFE_FUNCTIONS[node.id]
        raise ValueError(f"Name {node.id} is not allowed")
    elif isinstance(node, ast.Expression):
        return safe_eval_node(node.body)
    else:
        raise ValueError(f"Unsupported expression type: {type(node).__name__}")

@app.route("/evalcode", methods=['POST'])
def eval_code():
    """
    Safely evaluate mathematical expressions only.
    Uses a custom AST evaluator with whitelisted operators and functions.
    """
    try:
        # Get user input from request
        user_code = request.json.get('code', '') if request.is_json else request.form.get('code', '')

        if not user_code:
            return jsonify({'error': 'No code provided'}), 400

        # Parse the code to check for malicious content
        try:
            tree = ast.parse(user_code, mode='eval')
        except SyntaxError as e:
            return jsonify({'error': f'Invalid syntax: {str(e)}'}), 400

        # Additional validation to ensure only allowed nodes
        for node in ast.walk(tree):
            if isinstance(node, (ast.Import, ast.ImportFrom, ast.Exec, ast.Eval)):
                return jsonify({'error': f'{type(node).__name__} statements are not allowed'}), 400
            elif isinstance(node, ast.Call):
                if isinstance(node.func, ast.Attribute):
                    return jsonify({'error': 'Method calls are not allowed'}), 400
            elif isinstance(node, ast.Attribute):
                return jsonify({'error': 'Attribute access is not allowed'}), 400
            elif isinstance(node, ast.Subscript):
                return jsonify({'error': 'Subscript access is not allowed'}), 400
            elif isinstance(node, ast.Lambda):
                return jsonify({'error': 'Lambda expressions are not allowed'}), 400
            elif isinstance(node, ast.ListComp, ast.SetComp, ast.DictComp, ast.GeneratorExp):
                return jsonify({'error': 'Comprehensions are not allowed'}), 400

        # Safe evaluation using our custom evaluator
        try:
            result = safe_eval_node(tree)
            return jsonify({
                'result': str(result),
                'output': ''
            })
        except Exception as e:
            return jsonify({'error': f'Execution error: {str(e)}'}), 400

    except Exception as e:
        return jsonify({'error': f'Server error: {str(e)}'}), 500

