def evalInput(inputStr):
    import ast
    try:
        # Parse the input to ensure it's a valid expression
        node = ast.parse(inputStr, mode='eval')
        # Only allow literal expressions for safety
        if not isinstance(node.body, ast.Constant):
            raise ValueError("Only literal values are allowed")
        return ast.literal_eval(inputStr)
    except (ValueError, SyntaxError) as e:
        raise ValueError("Invalid input expression") from e

import pickle
from django.conf.urls import url


def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("Input must be bytes")

    if len(pickled) > 1024 * 1024:  # 1MB limit
        raise ValueError("Pickle data too large")

    try:
        # Use pickle's safe loading
        return pickle.loads(pickled)
    except (pickle.PickleError, EOFError, AttributeError, ImportError, IndexError) as e:
        raise ValueError("Invalid pickle data") from e

import json
from django.conf.urls import url


def getSerializedData(serialized):
    '''
    Return deserialized data
    '''
    if not isinstance(serialized, (str, bytes)):
        raise TypeError("Input must be string or bytes")

    if isinstance(serialized, bytes):
        try:
            serialized = serialized.decode('utf-8')
        except UnicodeDecodeError as e:
            raise ValueError("Invalid UTF-8 encoding") from e

    if len(serialized) > 1024 * 1024:  # 1MB limit
        raise ValueError("Serialized data too large")

    try:
        return json.loads(serialized)
    except (json.JSONDecodeError, TypeError, ValueError) as e:
        raise ValueError("Invalid serialized data") from e

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    try:
        yaml_data = request.get_data(as_text=True)
        parsed_data = yaml.safe_load(yaml_data)
        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({'error': 'Invalid YAML format', 'details': str(e)}), 400
    except Exception as e:
        return jsonify({'error': 'Internal server error', 'details': str(e)}), 500
